-- STEP 1: query [kommuner]
SELECT objid, kommunenummer, kommunenavn, omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Trondheim%' AND kommunenummer IS NOT NULL;

-- STEP BOUNDARY --

-- STEP 2: query [kvikkleire]
SELECT utlopomr.objid AS hazard_id, utlopomr.omrade AS hazard_geom FROM kvikkleire.kvikkleire_87067f98e29a47d4901328f3a926a515.utlopomr JOIN kvikkleire.kvikkleire_87067f98e29a47d4901328f3a926a515.skredrisikokvikkleireklasse ON utlopomr.skredrisikokvikkleireklasse = skredrisikokvikkleireklasse.identifier WHERE skredrisikokvikkleireklasse.description = 'Høy' AND ST_Intersects(utlopomr.omrade, ST_GeomFromGeoJSON('{'type': 'Polygon', 'coordinates': [[%(trondheim_coords)s]]}'));
